#! /usr/bin/env python3

import os
from pathlib import Path


def main():
    if os.getuid() != 0:
        raise SystemExit("This script needs sudo")

    sshd_config_dir = Path("/etc/ssh/sshd_config.d/")
    if not sshd_config_dir.exists():
        raise SystemExit(
            f"{sshd_config_dir} doesn't exist. Is openssh-server installed?"
        )
    # filename is the same as the one generated by deployment ci
    with open(sshd_config_dir / "oemqa_no_password.conf", 'w') as f:
        f.write("PasswordAuthentication no\n")


if __name__ == "__main__":
    main()
